194: pub fn parse_stop_reason(s: Option<&str>) -> StopReason {
195:     let result = match s {
196:         Some("end_turn") => StopReason::EndTurn,
197:         Some("tool_use") => StopReason::ToolUse,
198:         // Server-side sampling loop hit its iteration cap. The runtime
199:         // must re-send the conversation without injecting a synthetic
200:         // user message; the server resumes the loop where it left off.
201:         // See StopReason::PauseTurn docs and cli.js v142:622686.
202:         Some("pause_turn") => StopReason::PauseTurn,
203:         Some("max_tokens") => StopReason::MaxTokens,
204:         Some("stop_sequence") => StopReason::StopSequence,
205:         Some(other) => {
206:             // Unknown stop_reason string. Surface loudly — every
207:             // historical "stream silently ends" bug has eventually
208:             // traced back to a new server stop_reason being bucketed
209:             // into Other(...) and falling through event_loop's
210:             // dispatch ladder. The warn gives us a one-grep way to
211:             // catch the next variant (e.g. "refusal", "container_*")
212:             // before users notice.
213:             tracing::warn!(
214:                 target: "jfc::provider::sse",
215:                 stop_reason = other,
216:                 "parse_stop_reason: unknown stop_reason string — bucketing into Other(...) \
217:                  (event_loop will fall into the 'model said its piece' branch); \
218:                  check cli.js v142 for a new variant we need to map"
219:             );
220:             StopReason::Other(other.to_owned())
221:         }
222:         None => {
223:             // Missing stop_reason field. Anthropic sometimes omits it
224:             // on truncated streams or context_hint short-circuits. The
225:             // EndTurn default is most-conservative for back-compat
226:             // (closes the streaming slot cleanly) but the silent fall-
227:             // through is exactly the class of bug that hid pause_turn
228:             // for months. Warn loudly so future occurrences are
229:             // diagnosable from the trace log alone.
230:             tracing::warn!(
231:                 target: "jfc::provider::sse",
232:                 "parse_stop_reason: missing stop_reason field — defaulting to EndTurn \
233:                  (this is back-compat; if you see this paired with a stalled stream, \
234:                  the upstream omitted a real stop_reason we should be handling)"
235:             );
236:             StopReason::EndTurn
237:         }
238:     };
239:     tracing::trace!(
240:         target: "jfc::provider::sse",
241:         input = ?s,
242:         result = ?result,
243:         "parse_stop_reason"
244:     );
245:     result
246: }
