77: /// Load the config from disk. Returns `Ok(None)` when the file is absent so
78: /// callers can distinguish "not set up" from "set up but malformed".
79: pub fn load_config(path: &PathBuf) -> anyhow::Result<Option<BedrockConfig>> {
80:     let raw = match std::fs::read_to_string(path) {
81:         Ok(s) => s,
82:         Err(e) if e.kind() == std::io::ErrorKind::NotFound => return Ok(None),
83:         Err(e) => return Err(e.into()),
84:     };
85:     let cfg: BedrockConfig = toml::from_str(&raw)?;
86:     Ok(Some(cfg))
