89: /// Persist the config. Creates parent dirs as needed; overwrites atomically.
90: pub fn save_config(path: &PathBuf, cfg: &BedrockConfig) -> anyhow::Result<()> {
91:     if let Some(parent) = path.parent() {
92:         std::fs::create_dir_all(parent)?;
93:     }
94:     let body = toml::to_string_pretty(cfg)?;
95:     std::fs::write(path, body)?;
96:     Ok(())
97: }
