255: /// Synchronously check whether the configured profile (or default) can fetch
256: /// caller identity via STS. Used by the wizard's "test creds" step. Returns
257: /// the identity ARN on success.
258: pub fn check_caller_identity(cfg: &BedrockConfig) -> anyhow::Result<String> {
259:     let mut cmd = std::process::Command::new("aws");
260:     cmd.args([
261:         "sts",
262:         "get-caller-identity",
263:         "--query",
264:         "Arn",
265:         "--output",
266:         "text",
267:     ])
268:     .arg("--region")
269:     .arg(cfg.region_or_default());
270:     if let Some(profile) = cfg.profile.as_deref() {
271:         cmd.args(["--profile", profile]);
272:     }
273:     let out = cmd.output()?;
274:     if !out.status.success() {
275:         let stderr = String::from_utf8_lossy(&out.stderr);
276:         anyhow::bail!("aws sts get-caller-identity failed: {}", stderr.trim());
277:     }
278:     let arn = String::from_utf8(out.stdout)?.trim().to_owned();
279:     if arn.is_empty() {
280:         anyhow::bail!("STS returned an empty ARN — credentials may be unset");
281:     }
282:     Ok(arn)
283: }
